+fn contains_unsupported_in_result_column(col: &ResultColumn) -> bool {
+    match col {
+        ResultColumn::Expr { expr, .. } => contains_unsupported_in_expr(expr),
+        ResultColumn::Star | ResultColumn::TableStar(_) => false,
+    }
+}
